  WHEN 1 THEN 200.00
  WHEN 2 THEN 440.00
  WHEN 10 THEN 510.00
  WHEN 15 THEN 390.00
  WHEN 20 THEN 610.00
  WHEN 31 THEN 590.00
  ELSE `valorTotal`
END
